        html: "&nbsp;\n\n<img alt=\"\" src=\"http://www.cernahealth.com/wp-content/plugins/wp-o-matic/cache/23a9d_9AD_uxZ5kRM\" width=\"1\" height=\"1\" /><a href=\"https://www.thecernafoundation.org/CernaHomeCare/wp-content/uploads/2013/10/holidays_Cerna.jpg\"><img class=\"aligncenter size-full wp-image-933\" alt=\"holidays_Cerna\" src=\"https://www.thecernafoundation.org/CernaHomeCare/wp-content/uploads/2013/10/holidays_Cerna.jpg\" width=\"266\" height=\"266\" /></a>",
